[CmdletBinding()]param([Parameter(Mandatory)][string]$BundlePath,[string]$Version='1.0.0',[switch]$AllowUnsignedPrerelease)
$ErrorActionPreference='Stop';$expected=@('WinLic-Setup.exe',"WinLic-$Version-sbom.spdx.json","WinLic-$Version-release-manifest.json","WinLic-$Version-SHA256SUMS.txt",'RELEASE-NOTES.md','VERIFY.md');$actual=@(Get-ChildItem $BundlePath -File|ForEach-Object Name);$extra=@($actual|Where-Object{$_-notin$expected});$missing=@($expected|Where-Object{$_-notin$actual});if($extra-or$missing){throw "Bundle allowlist mismatch. Extra=$extra Missing=$missing"};if(-not$AllowUnsignedPrerelease-and(Get-AuthenticodeSignature (Join-Path $BundlePath 'WinLic-Setup.exe')).Status-ne'Valid'){throw 'Unsigned stable release rejected.'};if($AllowUnsignedPrerelease-and(Split-Path $BundlePath -Leaf)-notmatch 'rc\.\d+-unsigned$'){throw 'Unsigned RC naming policy failed.'};$manifest=Get-Content (Join-Path $BundlePath "WinLic-$Version-release-manifest.json") -Raw|ConvertFrom-Json;if($manifest.version-ne$Version){throw 'Manifest version mismatch.'};$lines=Get-Content (Join-Path $BundlePath "WinLic-$Version-SHA256SUMS.txt");foreach($line in $lines){if($line-match '^([A-F0-9]{64})  (.+)$'){if((Get-FileHash (Join-Path $BundlePath $Matches[2]) -Algorithm SHA256).Hash-ne$Matches[1]){throw "Checksum mismatch: $($Matches[2])"}}};$text=(Get-ChildItem $BundlePath -File|Where-Object Extension -in '.json','.md','.txt'|Get-Content -Raw)-join"`n";if($text-match 'C:\\Users\\|D:\\Tools\\|BEGIN PRIVATE KEY|access.?token|refresh.?token'){throw 'Bundle sensitive-data scan failed.'};Write-Host 'Release bundle verification PASS'
